toBounds(sizeInMeters) {
	const latAccuracy = 180 * sizeInMeters / 40075017,
	lngAccuracy = latAccuracy / Math.cos((Math.PI / 180) * this.lat);

	return new LatLngBounds(
		[this.lat - latAccuracy, this.lng - lngAccuracy],
		[this.lat + latAccuracy, this.lng + lngAccuracy]);
}

export function ancestor(node, visitors, baseVisitor, state, override) {
  let ancestors = []
  if (!baseVisitor) baseVisitor = base
  ;(function c(node, st, override) {
    let type = override || node.type
    let isNew = node !== ancestors[ancestors.length - 1]
    if (isNew) ancestors.push(node)
    visitNode(baseVisitor, type, node, st, c)
    if (visitors[type]) visitors[type](node, st || ancestors, ancestors)
    if (isNew) ancestors.pop()
  })(node, state, override)
}

export function fullAncestor(node, callback, baseVisitor, state) {
  if (!baseVisitor) baseVisitor = base
  let ancestors = [], last
  ;(function c(node, st, override) {
    let type = override || node.type
    let isNew = node !== ancestors[ancestors.length - 1]
    if (isNew) ancestors.push(node)
    visitNode(baseVisitor, type, node, st, c)
    if (last !== node) {
      callback(node, st || ancestors, ancestors, type)
      last = node
    }
    if (isNew) ancestors.pop()
  })(node, state)
}

export function findNodeBefore(node, pos, test, baseVisitor, state) {
  test = makeTest(test)
  if (!baseVisitor) baseVisitor = base
  let max
  ;(function c(node, st, override) {
    if (node.start > pos) return
    let type = override || node.type
    if (node.end <= pos && (!max || max.node.end < node.end) && test(type, node))
      max = new Found(node, st)
    visitNode(baseVisitor, type, node, st, c)
  })(node, state)
  return max
}

const dayjs = function (date, c) {
  if (isDayjs(date)) {
    return date.clone()
  }
  // eslint-disable-next-line no-nested-ternary
  const cfg = typeof c === 'object' ? c : {}
  cfg.date = date
  cfg.args = arguments// eslint-disable-line prefer-rest-params
  return new Dayjs(cfg) // eslint-disable-line no-use-before-define
}

export const getPath = path => {
  const parsedTargets = parseTargets(path);
  const $parsedSvg = /** @type {SVGGeometryElement} */(parsedTargets[0]);
  if (!$parsedSvg || !isSvg($parsedSvg)) return console.warn(`${path} is not a valid SVGGeometryElement`);
  return $parsedSvg;
}

pad(bufferRatio) {
	const min = this.min,
	max = this.max,
	heightBuffer = Math.abs(min.x - max.x) * bufferRatio,
	widthBuffer = Math.abs(min.y - max.y) * bufferRatio;


	return new Bounds(
		new Point(min.x - heightBuffer, min.y - widthBuffer),
		new Point(max.x + heightBuffer, max.y + widthBuffer));
}

_transform(point, scale) {
	scale ||= 1;
	point.x = scale * (this._a * point.x + this._b);
	point.y = scale * (this._c * point.y + this._d);
	return point;
}

// @method untransform(point: Point, scale?: Number): Point
// Returns the reverse transformation of the given point, optionally divided
// by the given scale. Only accepts actual `Point` instances, not arrays.
untransform(point, scale) {
	scale ||= 1;
	return new Point(
		(point.x / scale - this._b) / this._a,
		(point.y / scale - this._d) / this._c);
}

function printEnumMember(path, options, print) {
  const { node } = path;
  const isTsEnumMember = node.type === "TSEnumMember";

  const idDoc = isTsEnumMember
    ? printKey(path, options, print)
    : // Flow only allow identifier
      print("id");
  const initializerProperty = isTsEnumMember ? "initializer" : "init";
  if (!node[initializerProperty]) {
    return idDoc;
  }

  return [idDoc, " = ", print(initializerProperty)];
}

const getRequireEsmModuleExportsAccess = (
	importedModule,
	moduleGraph,
	runtime
) => {
	if (!isRequireEsmModuleExportsModule(importedModule, moduleGraph)) {
		return null;
	}
	const exportsInfo = moduleGraph.getExportsInfo(importedModule);
	// CJS exports are never inlined
	const usedName = exportsInfo.getUsedName([ESM_MODULE_EXPORTS_NAME], runtime);
	if (usedName === false) return null;
	return propertyAccess(/** @type {readonly string[]} */ (usedName));
};

export function findNodeAround(node, pos, test, baseVisitor, state) {
  test = makeTest(test)
  if (!baseVisitor) baseVisitor = base
  try {
    (function c(node, st, override) {
      let type = override || node.type
      if (node.start > pos || node.end < pos) return
      visitNode(baseVisitor, type, node, st, c)
      if (test(type, node)) throw new Found(node, st)
    })(node, state)
  } catch (e) {
    if (e instanceof Found) return e
    throw e
  }
}

export function findNodeAfter(node, pos, test, baseVisitor, state) {
  test = makeTest(test)
  if (!baseVisitor) baseVisitor = base
  try {
    (function c(node, st, override) {
      if (node.end < pos) return
      let type = override || node.type
      if (node.start >= pos && test(type, node)) throw new Found(node, st)
      visitNode(baseVisitor, type, node, st, c)
    })(node, state)
  } catch (e) {
    if (e instanceof Found) return e
    throw e
  }
}

